class Inventory:
    def __init__(self, stock: int):
        self.stock = stock
        self.reserved = 0

    def reserve(self, qty: int) -> None:
        """Reserve qty units if available; otherwise raise ValueError."""
        if qty > self.available():
            raise ValueError("insufficient stock")
        self.reserved += qty

    def release(self, qty: int) -> None:
        """Release qty units back to available inventory."""
        self.reserved -= qty
        if self.reserved < 0:
            # Guard against inconsistent calls; keep behavior explicit.
            self.reserved = 0

    def available(self) -> int:
        return self.stock - self.reserved


class Wallet:
    def __init__(self, balance: int):
        self.balance = balance

    def charge(self, amount: int) -> None:
        """Charge amount from the wallet; otherwise raise ValueError."""
        if amount > self.balance:
            raise ValueError("insufficient funds")
        self.balance -= amount


def place_order(inventory: Inventory, wallet: Wallet, qty: int, price: int) -> dict:
    """Reserve inventory, then charge wallet. Roll back reservation on failure."""
    inventory.reserve(qty)
    total = qty * price
    try:
        wallet.charge(total)
    except ValueError:
        inventory.release(qty)
        raise

    return {"status": "confirmed", "qty": qty, "total": total}
