from __future__ import annotations


def compute_raw_stats(data):
    """Compute statistics on raw (untransformed) data.

    Returns zero stats for empty input.
    """
    if not data:
        return {"raw_max": 0, "raw_min": 0, "raw_sum": 0}

    return {
        "raw_max": max(data),
        "raw_min": min(data),
        "raw_sum": sum(data),
    }


def normalize(data):
    """Normalize numeric data to the 0-1 range.

    For empty input, returns an empty list. If all values are equal,
    returns 0.5 for each element.
    """
    if not data:
        return []

    lo = min(data)
    hi = max(data)
    if hi == lo:
        return [0.5] * len(data)

    return [(x - lo) / (hi - lo) for x in data]


def pipeline(data):
    """Run pipeline.

    Requirement: raw_stats MUST reflect the original data, not the normalized version.

    Returns:
        dict: {"raw_stats": ..., "cleaned": ...}
