from config import create_config


class ConfigMiddleware:
    """Middleware that keeps an immutable base config and returns per-request configs."""

    def __init__(self):
        # Cached base config; must not be mutated per request.
        self._base = create_config()

    def apply_config(self, request_overrides=None):
        """Return config for this request, applying any overrides."""
        if request_overrides:
            return create_config({**self._base, **request_overrides})
        # Return a fresh dict anyway to guarantee isolation.
        return create_config(self._base)

    def get_timeout(self):
        return self._base.get("timeout", 30)


