class Inventory:
    def __init__(self, stock):
        self.stock = stock
        self.reserved = 0

    def reserve(self, qty):
        """Reserve qty units if available; otherwise raise."""
        if qty > self.available():
            raise ValueError("insufficient stock")
        self.reserved += qty

