class Inventory:
    def __init__(self, stock):
        self.stock = stock
        self.reserved = 0

    def reserve(self, qty):
        if qty < 0:
            raise ValueError("qty must be non-negative")
        available = self.stock - self.reserved
        if qty > available:
            raise ValueError("insufficient stock")
        self.reserved += qty

    def release(self, qty):
        if qty < 0:
            raise ValueError("qty must be non-negative")
        if qty > self.reserved:
            raise ValueError("cannot release more than reserved")
        self.reserved -= qty

    def available(self):
        return self.stock - self.reserved


class Wallet:
    def __init__(self, balance):
        self.balance = balance

    def charge(self, amount):
        if amount < 0:
            raise ValueError("amount must be non-negative")
        if amount > self.balance:
            raise ValueError("insufficient funds")
        self.balance -= amount


def place_order(inventory, wallet, qty, price):
    """Reserve inventory, then charge wallet. Release on failure."""
    inventory.reserve(qty)
    total = qty * price
    try:
        wallet.charge(total)
    except ValueError:
        # If charging fails, release the inventory reservation and re-raise.
        inventory.release(qty)
        raise

    return {"status": "confirmed", "qty": qty, "total": total}
