from __future__ import annotations

from dataclasses import dataclass
from typing import Any, List, Optional, Tuple


@dataclass
class _ReportState:
    labels: List[Any]
    values: List[Any]


_state = _ReportState(labels=[], values=[])


def add_entry(label: Any, value: Any, position: Optional[int] = None) -> None:
    """Add an entry to the report.

    If position is provided, insert both label and value at that index so that
    indexes remain aligned.

    Otherwise, append both to the end.
    """
    if position is not None:
        _state.labels.insert(position, label)
        _state.values.insert(position, value)
    else:
        _state.labels.append(label)
        _state.values.append(value)


def get_entry(index: int) -> Tuple[Any, Any]:
    """Return (label, value) at the given index."""
    return _state.labels[index], _state.values[index]


def get_all() -> List[Tuple[Any, Any]]:
    """Return a list of (label, value) tuples."""
    return list(zip(_state.labels, _state.values))


def count() -> int:
    """Return the number of entries."""
    return len(_state.labels)


def reset() -> None:
    """Clear all entries."""
    _state.labels.clear()
    _state.values.clear()
